-- MySQL Database Schema for cchc_clinic_db\n\nCREATE DATABASE IF NOT EXISTS cchc_clinic_db;\nUSE cchc_clinic_db;\n\n-- Users Table\nCREATE TABLE IF NOT EXISTS users (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    username VARCHAR(255) NOT NULL UNIQUE,\n    password VARCHAR(255) NOT NULL,\n    email VARCHAR(255) NOT NULL UNIQUE,\n    role ENUM('admin', 'staff', 'patient') NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- Clinics Table\nCREATE TABLE IF NOT EXISTS clinics (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    address VARCHAR(255) NOT NULL,\n    phone VARCHAR(20),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- Services Table\nCREATE TABLE IF NOT EXISTS services (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    description TEXT,\n    price DECIMAL(10, 2) NOT NULL,\n    clinic_id INT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (clinic_id) REFERENCES clinics(id) ON DELETE SET NULL\n);\n\n-- Timeslots Table\nCREATE TABLE IF NOT EXISTS timeslots (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    start_time DATETIME NOT NULL,\n    end_time DATETIME NOT NULL,\n    service_id INT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (service_id) REFERENCES services(id) ON DELETE CASCADE\n);\n\n-- Appointments Table\nCREATE TABLE IF NOT EXISTS appointments (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    user_id INT,\n    timeslot_id INT,\n    appointment_date DATE NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,\n    FOREIGN KEY (timeslot_id) REFERENCES timeslots(id) ON DELETE CASCADE\n);\n\n-- Queue Table\nCREATE TABLE IF NOT EXISTS queue (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    appointment_id INT,\n    status ENUM('waiting', 'in_progress', 'completed') NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (appointment_id) REFERENCES appointments(id) ON DELETE CASCADE\n);\n\n-- Notifications Table\nCREATE TABLE IF NOT EXISTS notifications (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    user_id INT,\n    message TEXT NOT NULL,\n    is_read BOOLEAN DEFAULT FALSE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\n-- Analytics Table\nCREATE TABLE IF NOT EXISTS analytics (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    user_id INT,\n    service_id INT,\n    visit_date DATE NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,\n    FOREIGN KEY (service_id) REFERENCES services(id) ON DELETE CASCADE\n);\n\n-- Audit Log Table\nCREATE TABLE IF NOT EXISTS audit_log (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    action VARCHAR(255) NOT NULL,\n    user_id INT,\n    service_id INT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL,\n    FOREIGN KEY (service_id) REFERENCES services(id) ON DELETE SET NULL\n);\n\n-- Indexes (if needed)\nCREATE INDEX idx_user ON appointments(user_id);\nCREATE INDEX idx_service ON services(clinic_id);\nCREATE INDEX idx_timeslot ON timeslots(service_id);\nCREATE INDEX idx_queue ON queue(appointment_id);